const items = $input.all();
return items.map(item => {
  const d = item.json;
  if (d.author?.bot) return null;
  return {
    json: {
      channel: 'discord',
      sender_id: d.author?.id || 'unknown',
      sender_name: d.author?.username || 'unknown',
      body: d.content || '',
      raw_metadata: JSON.stringify({ channel_id: d.channel_id, guild_id: d.guild_id, message_id: d.id }),
      status: 'unread'
    }
  };
}).filter(Boolean);
